mapper.select:
SELECT room_id as roomId, room_no as roomNo, room_type as roomType, price, status, isdel, del_date as delDate
FROM (
SELECT a.*, ROWNUM rn FROM (
SELECT * FROM hotel_room

    isdel = 1
    
        AND (room_no LIKE '%' || #{keyword} || '%' OR room_type LIKE '%' || #{keyword} || '%')
    

ORDER BY room_id DESC
) a WHERE ROWNUM <= #{endRow}
) WHERE rn > #{startRow}

mapper.update:
UPDATE hotel_room
SET room_no = #{roomNo},
    room_type = #{roomType},
    price = #{price},
    status = #{status}
WHERE room_id = #{roomId}

UPDATE hotel_room
SET isdel = 0, del_date = SYSDATE
WHERE room_id = #{roomId}
